import random

class CartItem:
    def __init__(self, product_id, quantity):
        self.product_id = product_id
        self.quantity = quantity

class User:
    def __init__(self, user_id, tier):
        self.user_id = user_id
        self.tier = tier

def validate_cart_items(cart_items):
    # Simulate validation logic
    for item in cart_items:
        if item.quantity <= 0:
            raise ValueError("Invalid quantity")
    return True

def apply_discount_code(discount_code, user):
    # Simulate discount code application logic
    valid_codes = {
        'ADMIN10': ['admin'],
        'VIP5': ['vip', 'premium']
    }
    
    if discount_code in valid_codes:
        if user.tier not in valid_codes[discount_code]:
            raise ValueError("Invalid discount code for user tier")
        return 0.9  # 10% discount
    else:
        raise ValueError("Invalid discount code")

def calculate_tax(total, tax_rate):
    # Simulate tax calculation logic
    return total * (tax_rate / 100)

def process_payment(total):
    # Simulate payment processing logic
    print(f"Processing payment of ${total:.2f}")
    return True

def create_order_record(user, cart_items, discount_code=None, tax_rate=8.25):
    try:
        if not validate_cart_items(cart_items):
            raise ValueError("Cart items validation failed")
        
        total = sum(item.quantity * 10 for item in cart_items)  # Simulated product price
        
        if discount_code:
            discount_rate = apply_discount_code(discount_code, user)
            total *= discount_rate
        
        tax_amount = calculate_tax(total, tax_rate)
        final_total = total + tax_amount
        
        if not process_payment(final_total):
            raise ValueError("Payment processing failed")
        
        print(f"Order created for user {user.user_id} with total ${final_total:.2f}")
    except Exception as e:
        print(f"Error: {e}")

# Example usage
cart_items = [CartItem(1, 2), CartItem(2, 3)]
